What does this program print?

```cpp
#include <iostream>
template <typename T, int N>
class Stack {
    T data_[N]{};
    int top_{0};
public:
    void push(T v) { if (top_ < N) data_[top_++] = v; }
    T   top()  const { return data_[top_ - 1]; }
    int count() const { return top_; }
};
int main() {
    Stack<int, 4> s;
    s.push(10);
    s.push(20);
    s.push(30);
    std::cout << s.count() << " " << s.top() << "\n";
}
```
